class Leaf:
    def operation(self):
        return "L"

class Composite:
    def __init__(self):
        self.children = []
    def add(self, c):
        self.children.append(c)
    def operation(self):
        return "C(" + "+".join(ch.operation() for ch in self.children) + ")"

c = Composite()
c.add(Leaf())
c.add(Leaf())
print(c.operation())
